import{_ as t,o,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"G07: 研發成果實質性 — 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3163_波若威/20260502/G07_研發成果實質性.md","filePath":"審計報告庫/經營審計/3163_波若威/20260502/G07_研發成果實質性.md"}'),l={name:"審計報告庫/經營審計/3163_波若威/20260502/G07_研發成果實質性.md"};function i(n,a,s,h,g,d){return o(),r("div",null,[...a[0]||(a[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g07-研發成果實質性-—-經營審計專家報告" tabindex="-1">G07: 研發成果實質性 — 經營審計專家報告 <a class="header-anchor" href="#g07-研發成果實質性-—-經營審計專家報告" aria-label="Permalink to &quot;G07: 研發成果實質性 — 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>最近三年研發成果預期項目是否有如期完成？最近三年重大研發成果為何？具備何種變現潛力？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：研發轉向AI資料中心方案：800G/1.6T光纖套件已獲Google訂單出貨，CPO驗證中目標2026量產。研發費率3-5%，屬中低水準。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年度</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>B（持平）</strong>：研發費用（營運費用中未拆分細項，估算季研發費用率3-5%），年研發費用估約1.5-2.5億，低於華星光（估年研費&gt;3億）但優於上詮（~1億）。研發方向正確（CPO/800G/矽光子），但研發集約度偏低——2023年營收高峰27.79億時研發佔比更低。重大成果：CPO模組送樣驗證中（vs原訂2025H2小量出貨→進度略延）、光纖套件獲Google採用（達成）。整體研發落地率約60-70%，部分成果（CPO量產、1.6T認證）尚在進行中。專利佈局資訊不足，無法判定專利牆深度。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="重大研發成果" tabindex="-1">重大研發成果 <a class="header-anchor" href="#重大研發成果" aria-label="Permalink to &quot;重大研發成果&quot;">​</a></h3><ul><li><strong>核心重點</strong>：(1)800G/1.6T光纖套件獲Google驗證Q3出貨；(2)CPO交換器模組送樣目標2026量產；(3)FAU端面處理技術送樣NVIDIA。</li><li><strong>深度見解</strong>：研發從FTTx被動元件(毛利率8-15%)轉向AI方案，價值鏈上移。CPO量產從2025H2延至2026H1，屬合理但反映技術整合難度。</li></ul><h3 id="研發效率" tabindex="-1">研發效率 <a class="header-anchor" href="#研發效率" aria-label="Permalink to &quot;研發效率&quot;">​</a></h3><ul><li><strong>核心重點</strong>：研發費率3-5%低於華星光(5-8%)及聯亞(10-15%)。Google訂單貢獻營收估3-4億(15-18%)，ROI約1.5-2倍。</li><li><strong>深度見解</strong>：精實型策略聚焦後段製程，投入不到聯亞一半但CPO能見度相近。關鍵風險：FAU量產良率能否達NVIDIA ppm等級要求尚無法驗證。</li></ul><h3 id="變現潛力" tabindex="-1">變現潛力 <a class="header-anchor" href="#變現潛力" aria-label="Permalink to &quot;變現潛力&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2026年光纖套件營收估8-12億(佔比35-45%)，CPO首年貢獻估1-3億。</li><li><strong>深度見解</strong>：CPO產業化爆發在2027-2028年，市場可能過早將獲利計入股價。800G套件競爭門檻不高，華星光/上詮均可量產，價格戰風險在2026H2浮現。</li></ul><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>CPO量產時程遞延的股價修正風險</strong>：市場已經將CPO量產（2026年）的預期計入股價，但CPO從驗證到真正貢獻營收通常需6-12個月爬坡。若2026Q1仍未見量產公告，股價可能面臨「預期落差」的修正壓力。2025年CPO驗證從H2延至H1（遞延約半年）已是一個警訊。</li><li><strong>研發費用率偏低恐結構性不足</strong>：以2025年營收22.26億、研發費用率3-5%推算，年研發支出約1.1-2.2億。相較華星光在400G/800G主動模組領域的鉅額研發投入，波若威的研發預算可能不足以支撐從被動元件跨入CPO模組的技術跳躍。未來若需增加研發人員或設備，費用率將顯著上升，侵蝕獲利。</li><li><strong>專利保護不足的技術護城河風險</strong>：光被動元件的專利多為製程改良型（非基礎專利），且許多核心技術（端面研磨、光纖陣列）為業界通用知識。波若威未揭露其專利組合的深度與廣度，這對NVIDIA等重視智財權的客戶可能構成供應鏈審查的潛在障礙。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：波若威研發成果與CPO進度（鉅亨網, 自由時報, CMoney, 2025-2026）</li><li><strong>web_search</strong>：波若威800G/1.6T產品認證與出貨（UDN, 工商時報, 2025）</li><li><strong>web_search</strong>：波若威研發費用率與研發方向（Wantgoo, Pocket, 2025）</li><li><strong>FinMind</strong>：TaiwanStockFinancialStatements (3163, 2023Q1-2025Q4) — 營業費用間接驗證</li><li><strong>web_search</strong>：台積電CPO試產與產業化時程（IEK, 2025）</li></ul>',19)])])}const u=t(l,[["render",i]]);export{c as __pageData,u as default};
